from extract import RDAPExtractor
from transform import RDAPTransformer
from load import RDAPPipeline

# -----------------------------
# Step 1: Extract
# -----------------------------
extractor = RDAPExtractor()

# Example individual resources
domain_file = extractor.extract_domain("google.com")
ip_file = extractor.extract_ip("8.8.8.8")
asn_file = extractor.extract_asn("15169")

extracted_files = [f for f in [domain_file, ip_file, asn_file] if f]

# Batch example
batch_resources = [
    {'type':'domain', 'identifier':'github.com'},
    {'type':'ip', 'identifier':'1.1.1.1'},
    {'type':'autnum', 'identifier':'16509'}
]
batch_files = extractor.extract_batch(batch_resources)
extracted_files.extend(batch_files)

print("Extracted files:", extracted_files)

# -----------------------------
# Step 2: Transform
# -----------------------------
transformer = RDAPTransformer()
transformed_data = transformer.transform_batch(extracted_files)
print(f"Transformed {len(transformed_data)} records")

# -----------------------------
# Step 3: Load
# -----------------------------
pipeline = RDAPPipeline()

# Load to JSON (default)
pipeline.run(transformed_data)

